// // This comment suggests that the ADC simulator outputs the bottom 8 bits of the input instead of the top 8 bits.
module adc_simulator (
    input [23:0] adc_input,
    output reg [7:0] adc_output
);
    always @(*) begin
        adc_output = adc_input[23:16]; // Take the top 8 bits
    end
endmodule
